def fibonacci(n):
    if n < 0:
        return 0
    def _fib(n):
        if n == 0:
            return (0, 1)
        a, b = _fib(n >> 1)
        c = a * ((b << 1) - a)
        d = a * a + b * b
        if n & 1:
            return (d, c + d)
        else:
            return (c, d)
    return _fib(n)[0]

